import React from 'react';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from './ui/card.tsx';
import { Button } from './ui/button.tsx';
import { Input } from './ui/input.tsx';
import { Badge } from './ui/badge.tsx';
import { Checkbox } from './ui/checkbox.tsx';
import { Select } from './ui/select.tsx';
import { useQuery, useMutation, api } from '../lib/convex.tsx';
import { cn } from '../lib/utils.ts';

type Todo = {
  _id: string;
  _creationTime: number;
  title: string;
  completed: boolean;
  priority: "low" | "medium" | "high";
};

const priorityColors = {
  low: "success" as const,
  medium: "warning" as const,
  high: "destructive" as const,
};

function TaskItem({
  task,
  onToggle,
  onDelete
}: {
  task: Todo;
  onToggle: () => void;
  onDelete: () => void;
}) {
  return (
    <div className={cn(
      "flex items-center gap-4 p-4 border rounded-lg transition-all",
      task.completed && "opacity-50 bg-muted"
    )}>
      <Checkbox
        checked={task.completed}
        onCheckedChange={onToggle}
      />
      <div className="flex-1 min-w-0">
        <p className={cn(
          "font-medium truncate",
          task.completed && "line-through text-muted-foreground"
        )}>
          {task.title}
        </p>
        <p className="text-xs text-muted-foreground">
          Created {new Date(task._creationTime).toLocaleDateString()}
        </p>
      </div>
      <Badge variant={priorityColors[task.priority]}>
        {task.priority}
      </Badge>
      <Button
        variant="ghost"
        size="sm"
        onClick={onDelete}
        className="text-destructive hover:text-destructive"
      >
        Delete
      </Button>
    </div>
  );
}

export function TaskList() {
  const todos = useQuery(api.todos.list) as Todo[] | undefined;
  const createTodo = useMutation(api.todos.create);
  const toggleTodo = useMutation(api.todos.toggle);
  const removeTodo = useMutation(api.todos.remove);

  const [newTitle, setNewTitle] = React.useState("");
  const [priority, setPriority] = React.useState<Todo["priority"]>("medium");

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTitle.trim()) return;

    await createTodo({ title: newTitle.trim(), priority });
    setNewTitle("");
  };

  const completedCount = todos?.filter(t => t.completed).length ?? 0;
  const totalCount = todos?.length ?? 0;

  return (
    <Card className="w-full max-w-2xl mx-auto">
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          Task Manager
          <Badge variant="secondary">
            {completedCount}/{totalCount} done
          </Badge>
        </CardTitle>
        <CardDescription>
          Real-time sync powered by Convex - running from the browser!
        </CardDescription>
      </CardHeader>
      <CardContent className="space-y-4">
        <form onSubmit={handleSubmit} className="flex gap-2">
          <Input
            placeholder="Add a new task..."
            value={newTitle}
            onChange={(e) => setNewTitle(e.target.value)}
            className="flex-1"
          />
          <Select
            value={priority}
            onChange={(e) => setPriority(e.target.value as Todo["priority"])}
            className="w-32"
          >
            <option value="low">Low</option>
            <option value="medium">Medium</option>
            <option value="high">High</option>
          </Select>
          <Button type="submit">Add Task</Button>
        </form>

        <div className="space-y-2">
          {todos === undefined ? (
            <div className="text-center py-8 text-muted-foreground">
              Loading tasks...
            </div>
          ) : todos.length === 0 ? (
            <div className="text-center py-8 text-muted-foreground">
              No tasks yet. Add one above!
            </div>
          ) : (
            todos.map((task) => (
              <TaskItem
                key={task._id}
                task={task}
                onToggle={() => toggleTodo({ id: task._id })}
                onDelete={() => removeTodo({ id: task._id })}
              />
            ))
          )}
        </div>
      </CardContent>
    </Card>
  );
}
